#[derive(Deserialize, Debug)]
struct CommandPayload {
    command: String,
    #[serde(default)]
    parameters: serde_json::Value,
}

#[derive(Debug)]
enum Command {
    Start { service_name: String },
    Stop { service_id: u32 },
    Restart { service_id: u32, force: bool },
    Status,
    Unknown,
}

impl fmt::Display for Command {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            Command::Start { service_name } => write!(f, "Start command for service: {}", service_name),
            Command::Stop { service_id } => write!(f, "Stop command for service ID: {}", service_id),
            Command::Restart { service_id, force } => write!(f, "Restart command for service ID: {} (force: {})", service_id, force),
            Command::Status => write!(f, "Status command"),
            Command::Unknown => write!(f, "Unknown command"),
        }
    }
}

impl From<CommandPayload> for Command {
    fn from(payload: CommandPayload) -> Self {
        match payload.command.to_lowercase().as_str() {
            "start" => {
                let service_name = payload.parameters.get("service_name")
                    .and_then(|v| v.as_str())
                    .unwrap_or("default")
                    .to_string();
                Command::Start { service_name }
            }
            "stop" => {
                let service_id = payload.parameters.get("service_id")
                    .and_then(|v| v.as_u64())
                    .unwrap_or(0) as u32;
                Command::Stop { service_id }
            }
            "restart" => {
                let service_id = payload.parameters.get("service_id")
                    .and_then(|v| v.as_u64())
                    .unwrap_or(0) as u32;
                let force = payload.parameters.get("force")
                    .and_then(|v| v.as_bool())
                    .unwrap_or(false);
                Command::Restart { service_id, force }
            }
            "status" => Command::Status,
            _ => Command::Unknown,
        }
    }
}

