class ApiService {
    private val logger = LoggerFactory.getLogger(ApiService::class.java)
    private val httpClient = HttpClient(CIO) {
        install(JsonFeature)
    }

    private val apis = listOf(
        "https://api.example.com/data1",
        "https://api.example.com/data2",
        "https://api.example.com/data3"
    )

    // Lambda for extracting user information
    private val extractUserInfo: (JsonObject) -> Map<String, String> = { json ->
        mapOf(
            "id" to (json["id"]?.jsonPrimitive?.content ?: ""),
            "name" to (json["name"]?.jsonPrimitive?.content ?: ""),
            "email" to (json["email"]?.jsonPrimitive?.content ?: "")
        )
    }

    // Lambda for extracting product information
    private val extractProductInfo: (JsonObject) -> Map<String, String> = { json ->
        mapOf(
            "productId" to (json["productId"]?.jsonPrimitive?.content ?: ""),
            "title" to (json["title"]?.jsonPrimitive?.content ?: ""),
            "price" to (json["price"]?.jsonPrimitive?.content ?: "")
        )
    }

    // Lambda for extracting transaction data
    private val extractTransactionInfo: (JsonObject) -> Map<String, String> = { json ->
        mapOf(
            "transactionId" to (json["transactionId"]?.jsonPrimitive?.content ?: ""),
            "amount" to (json["amount"]?.jsonPrimitive?.content ?: ""),
            "timestamp" to (json["timestamp"]?.jsonPrimitive?.content ?: "")
        )
    }

    // Mapping API URLs to their respective extraction functions
    private val apiProcessors = mapOf(
        apis[0] to extractUserInfo,
        apis[1] to extractProductInfo,
        apis[2] to extractTransactionInfo
    )

    suspend fun fetchAndProcessData(): String {
        val results = mutableListOf<Map<String, Any>>()

        coroutineScope {
            val deferredResults = apis.map { apiUrl ->
                async {
                    try {
                        logger.info("Fetching data from $apiUrl")
                        val response = httpClient.get<String>(apiUrl)
                        val jsonResponse = Json.parseToJsonElement(response).jsonObject

                        // Process the JSON using the appropriate lambda
                        val processor = apiProcessors[apiUrl] ?: error("No processor found for $apiUrl")
                        val processedData = processor(jsonResponse)

                        logger.info("Successfully processed data from $apiUrl")
                        mapOf(
                            "source" to apiUrl,
                            "timestamp" to LocalDateTime.now().toString(),
                            "data" to processedData
                        )
                    } catch (e: Exception) {
                        logger.error("Error processing $apiUrl: ${e.message}")
                        mapOf(
                            "source" to apiUrl,
                            "error" to e.message,
                            "timestamp" to LocalDateTime.now().toString()
                        )
                    }
                }
            }

            deferredResults.forEach {
                results.add(it.await())
            }
        }

        // Aggregate and summarize results
        val successCount = results.count { !it.containsKey("error") }
        val errorCount = results.size - successCount

        val summary = """
            |API Request Summary:
            |Total Requests: ${results.size}
            |Successful: $successCount
            |Failed: $errorCount
            |Timestamp: ${LocalDateTime.now()}
            |
            |Detailed Results:
            |${results.joinToString("\n") { it.toString() }}
        """.trimMargin()

        logger.info("Request summary: $successCount successful, $errorCount failed")

        return summary
    }
}

const elementObserver = (selector) => {
  const targetElement = document.querySelector(selector);

  if (!targetElement) {
    console.error(`Element with selector ${selector} not found.`);
    return;
  }

  const observer = new MutationObserver((mutations) => {
    mutations.forEach((mutation) => {
      const timestamp = new Date().toISOString();

      if (mutation.type === 'attributes') {
        console.log(`[${timestamp}] Attribute '${mutation.attributeName}' was modified on the observed element.`);
      } else if (mutation.type === 'childList') {
        if (mutation.addedNodes.length > 0) {
          console.log(`[${timestamp}] ${mutation.addedNodes.length} node(s) were added to the observed element.`);
        }
        if (mutation.removedNodes.length > 0) {
          console.log(`[${timestamp}] ${mutation.removedNodes.length} node(s) were removed from the observed element.`);
        }
      } else if (mutation.type === 'characterData') {
        console.log(`[${timestamp}] Text content was modified in the observed element.`);
      }
    });
  });

  observer.observe(targetElement, {
    attributes: true,
    childList: true,
    subtree: true,
    characterData: true
  });

  console.log(`Now monitoring changes to element: ${selector}`);

  return {
    stop: () => {
      observer.disconnect();
      console.log(`Stopped monitoring changes to element: ${selector}`);
    }
  };
};

function mergeAndAggregate(collection) {
  const merged = {};

  collection.forEach(item => {
    const { id, score } = item;

    if (merged[id]) {
      merged[id] = {
        ...merged[id],
        score: merged[id].score + score
      };
    } else {
      merged[id] = { ...item };
    }
  });

  return merged;
}

def extract_unique_even_numbers(lists):
    seen = set()
    result = []

    for num_list in lists:
        even_nums = [num for num in num_list if num % 2 == 0]
        for num in even_nums:
            if num not in seen:
                seen.add(num)
                result.append(num)

    return result

use std::collections::HashMap;
use std::io::{Read, Write};
use std::net::{TcpListener, TcpStream};
use std::sync::{Arc, Mutex};

type RouteHandler = Box<dyn Fn(&str) -> String + Send + Sync>;

struct Server {
    routes: HashMap<String, RouteHandler>,
}

impl Server {
    fn new() -> Self {
        Server {
            routes: HashMap::new(),
        }
    }

    fn add_route<F>(&mut self, path: &str, handler: F)
    where
        F: Fn(&str) -> String + Send + Sync + 'static,
    {
        self.routes.insert(path.to_string(), Box::new(handler));
    }

    fn handle_request(&self, mut stream: TcpStream) {
        let mut buffer = [0; 1024];
        stream.read(&mut buffer).unwrap();

        let request = String::from_utf8_lossy(&buffer[..]);
        let path = request.lines().next().unwrap_or("")
            .split_whitespace().nth(1).unwrap_or("/");

        let response = match self.routes.get(path) {
            Some(handler) => handler(path),
            None => "404 Not Found".to_string(),
        };

        let response = format!(
            "HTTP/1.1 200 OK\r\nContent-Type: text/html\r\nContent-Length: {}\r\n\r\n{}",
            response.len(),
            response
        );

        stream.write(response.as_bytes()).unwrap();
        stream.flush().unwrap();
    }

    fn start(&self, address: &str) {
        let listener = TcpListener::bind(address).unwrap();
        println!("Server running on {}", address);

        for stream in listener.incoming() {
            if let Ok(stream) = stream {
                let server = self.clone();
                std::thread::spawn(move || {
                    server.handle_request(stream);
                });
            }
        }
    }
}

impl Clone for Server {
    fn clone(&self) -> Self {
        let mut new_routes = HashMap::new();
        for (path, handler) in &self.routes {
            new_routes.insert(path.clone(), handler.clone());
        }
        Server { routes: new_routes }
    }
}

impl Clone for Box<dyn Fn(&str) -> String + Send + Sync> {
    fn clone(&self) -> Self {
        let handler = self.as_ref();
        Box::new(move |req| handler(req))
    }
}

fn main() {
    let mut server = Server::new();

    // Add route handlers using closures
    server.add_route("/", |_| {
        "<html><body><h1>Welcome to the Home Page</h1><p>Navigate to <a href='/about'>/about</a> or <a href='/contact'>/contact</a></p></body></html>".to_string()
    });

    server.add_route("/about", |_| {
        "<html><body><h1>About Us</h1><p>This is a Rust-based web server using closures for routing.</p></body></html>".to_string()
    });

    server.add_route("/contact", |_| {
        "<html><body><h1>Contact Us</h1><p>Email: example@example.com</p></body></html>".to_string()
    });

    // Dynamic content based on request
    server.add_route("/user", |req| {
        let user_id = if req.contains("?id=") {
            req.split("?id=").nth(1).unwrap_or("unknown").split("&").next().unwrap_or("unknown")
        } else {
