// ResizeRequest contains all necessary information for a resize operation
type ResizeRequest struct {
	ImageData  []byte
	Width      uint
	Height     uint
	Format     string
	ResponseCh chan ResizeResponse
	ID         int
}

// ResizeResponse contains the resized image data
type ResizeResponse struct {
	ImageData []byte
	Error     error
	ID        int
}

// ImageServer handles image resize requests
type ImageServer struct {
	requestCh chan ResizeRequest
	wg        sync.WaitGroup
	numWorkers int
}

// NewImageServer creates and initializes a new image server
func NewImageServer(numWorkers int) *ImageServer {
	server := &ImageServer{
		requestCh:  make(chan ResizeRequest, 100),
		numWorkers: numWorkers,
	}

	// Start the worker goroutines
	server.wg.Add(numWorkers)
	for i := 0; i < numWorkers; i++ {
		go server.worker(i)
	}

	return server
}

// worker continuously processes image resize requests
func (s *ImageServer) worker(id int) {
	defer s.wg.Done()
	log.Printf("Worker %d started", id)

	for req := range s.requestCh {
		log.Printf("Worker %d processing request %d", id, req.ID)

		// Decode the image
		img, format, err := image.Decode(bytes.NewReader(req.ImageData))
		if err != nil {
			req.ResponseCh <- ResizeResponse{
				Error: fmt.Errorf("failed to decode image: %v", err),
				ID:    req.ID,
			}
			continue
		}

		// If format is not specified in the request, use the original format
		if req.Format == "" {
			req.Format = format
		}

		// Resize the image
		resizedImg := resize.Resize(req.Width, req.Height, img, resize.Lanczos3)

		// Encode the resized image
		var buf bytes.Buffer
		var encodeErr error

		switch req.Format {
		case "jpeg", "jpg":
			encodeErr = jpeg.Encode(&buf, resizedImg, &jpeg.Options{Quality: 90})
		case "png":
			encodeErr = png.Encode(&buf, resizedImg)
		default:
			encodeErr = fmt.Errorf("unsupported image format: %s", req.Format)
		}

		if encodeErr != nil {
			req.ResponseCh <- ResizeResponse{
				Error: fmt.Errorf("failed to encode image: %v", encodeErr),
				ID:    req.ID,
			}
			continue
		}

		// Send the resized image back through the response channel
		req.ResponseCh <- ResizeResponse{
			ImageData: buf.Bytes(),
			ID:        req.ID,
		}

		log.Printf("Worker %d completed request %d", id, req.ID)
	}
}

// Shutdown stops the image server
