		if !filepath.IsAbs(imagePath) {
			var err error
			imagePath, err = filepath.Abs(imagePath)
			if err != nil {
				http.Error(w, "Invalid image path", http.StatusBadRequest)
				return
			}
		}

		imageData, err = os.ReadFile(imagePath)
		if err != nil {
			http.Error(w, "Failed to read image file: "+err.Error(), http.StatusNotFound)
			return
		}
	}

	// Increment request counter atomically
	requestID := *requestCounter
	*requestCounter++

	// Create a response channel for this specific request
	responseCh := make(chan ResizeResponse, 1)

	// Create a resize request and send it to the processing channel
	req := ResizeRequest{
		ImageData:  imageData,
		Width:      uint(width),
		Height:     uint(height),
		Format:     format,
		ResponseCh: responseCh,
		ID:         requestID,
	}

	// Send the request to the worker pool
	server.requestCh <- req

	// Wait for the response from the worker
	response := <-responseCh

	if response.Error != nil {
		http.Error(w, "Image processing error: "+response.Error.Error(), http.StatusInternalServerError)
		return
	}

	// Determine content type based on the format
	contentType := "image/jpeg"
	if format == "png" {
		contentType = "image/png"
	}

	// Send the resized image as a response
	w.Header().Set("Content-Type", contentType)
	w.Header().Set("Content-Length", strconv.Itoa(len(response.ImageData)))
	w.WriteHeader(http.StatusOK)
	w.Write(response.ImageData)
}

func main() {
	port := flag.Int("port", 8080, "Server port")
	numWorkers := flag.Int("workers", 4, "Number of worker goroutines")
	flag.Parse()

	log.Printf("Starting image server with %d workers on port %d", *numWorkers, *port)

	// Create the image server
	server := NewImageServer(*numWorkers)
	defer server.Shutdown()

	// Create a request counter
	var requestCounter int

	// Setup HTTP routes
	http.HandleFunc("/resize", func(w http.ResponseWriter, r *http.Request) {
