        {"name": "Edward Blake", "designation": "Developer", "salary": 70000.0}
    ]
    """.trimIndent()

    val employees = parseEmployees(jsonInput)
    processEmployees(employees)
}

fun parseEmployees(jsonInput: String): List<Employee> {
    return jsonInput
        .replace("[", "")
        .replace("]", "")
        .split("},")
        .map { 
            val cleanedJson = if (it.endsWith("}")) it else "$it}"
            val properties = cleanedJson
                .replace("{", "")
                .replace("}", "")
                .replace("\"", "")
                .split(",")
                .map { it.trim() }

            val name = properties.find { it.startsWith("name:") }?.split(": ")?.get(1) ?: ""
            val designation = properties.find { it.startsWith("designation:") }?.split(": ")?.get(1) ?: ""
            val salary = properties.find { it.startsWith("salary:") }?.split(": ")?.get(1)?.toDoubleOrNull() ?: 0.0

            Employee(name, designation, salary)
        }
}

fun processEmployees(employees: List<Employee>) {
    for (employee in employees) {
        val bonus = calculateBonus(employee)
        val privileges = determinePrivileges(employee)
        val tasks = assignTasks(employee)

        println("Employee: ${employee.name} (${employee.designation})")
        println("Salary: $${employee.salary}")
        println("Bonus: $${bonus}")
        println("Privileges: $privileges")
        println("Tasks: $tasks")
        println("------------------------")
    }
}

fun calculateBonus(employee: Employee): Double {
    return when (employee.designation) {
        "Manager" -> employee.salary * 0.2
        "Developer" -> employee.salary * 0.15
        "Intern" -> employee.salary * 0.05
        else -> 0.0
    }
}

fun determinePrivileges(employee: Employee): String {
