package main

import (
	"fmt"
	"log"
	"net/http"
	"time"
)

func processRequest(w http.ResponseWriter, r *http.Request) {
	requestID := fmt.Sprintf("%d", time.Now().UnixNano())
	log.Printf("Request received: %s - %s %s", requestID, r.Method, r.URL.Path)

	// Create a channel to communicate when processing is complete
	doneCh := make(chan struct{})
	errCh := make(chan error, 1)

	// Process request in a separate goroutine
	go func() {
		// Simulate opening resources that need to be closed
		log.Printf("Processing request %s: acquiring resources", requestID)

		// Defer cleanup of resources
		defer func() {
			log.Printf("Request %s: releasing resources", requestID)
			close(doneCh)
		}()

		// Simulate processing time
		time.Sleep(2 * time.Second)

		// Simulate potential error
		if r.URL.Path == "/error" {
			err := fmt.Errorf("simulated error for path /error")
			errCh <- err
			log.Printf("Request %s completed with error: %v", requestID, err)
			return
		}

		log.Printf("Request %s completed successfully", requestID)
	}()

	// Respond immediately while processing continues asynchronously
	w.WriteHeader(http.StatusAccepted)
	fmt.Fprintf(w, "Request accepted for processing\n")

	// Start another goroutine to monitor the processing status
	go func() {
		select {
		case err := <-errCh:
			log.Printf("Error channel received: %v", err)
		case <-doneCh:
			log.Printf("Done channel signaled for request %s", requestID)
		}
	}()
}

func main() {
	// Create a channel for graceful shutdown
	shutdownCh := make(chan struct{})

	http.HandleFunc("/", processRequest)

	serverAddr := ":8080"
	log.Printf("Server starting on %s", serverAddr)

	// Start server in a goroutine
	go func() {
		err := http.ListenAndServe(serverAddr, nil)
		if err != nil {
			log.Printf("Server failed: %v", err)
			close(shutdownCh)
		}
	}()

	// Wait for shutdown signal
	<-shutdownCh
	log.Println("Server shutting down")
}

fun main() {
    val todoList = mutableListOf<String>()
    var running = true

    println("Todo List Application")
    println("Available commands: add <task>, remove <index>, display, exit")

    while (running) {
        print("> ")
        val input = readLine() ?: ""
        val parts = input.split(" ", limit = 2)
        val command = parts[0].lowercase()

        when (command) {
            "add" -> {
                if (parts.size > 1) {
                    todoList.add(parts[1])
                    println("Task added: ${parts[1]}")
                } else {
                    println("Error: No task specified")
                }
            }
            "remove" -> {
                if (parts.size > 1) {
                    try {
                        val index = parts[1].toInt()
                        if (index >= 0 && index < todoList.size) {
                            val removedTask = todoList.removeAt(index)
                            println("Task removed: $removedTask")
                        } else {
                            println("Error: Invalid index")
                        }
                    } catch (e: NumberFormatException) {
                        println("Error: Index must be a number")
                    }
                } else {
                    println("Error: No index specified")
                }
            }
            "display" -> {
                if (todoList.isEmpty()) {
                    println("Todo list is empty")
                } else {
                    println("Todo List:")
                    todoList.forEachIndexed { index, task ->
                        println("$index: $task")
                    }
                }
            }
            "exit" -> {
                println("Exiting application")
                running = false
            }
            else -> {
                println("Unknown command. Available commands: add <task>, remove <index>, display, exit")
            }
        }
    }
}

