function aggregateWeatherData(weatherData) {
  try {
    const validTemperatures = Object.values(weatherData).filter(temp => temp !== null);

    if (validTemperatures.length === 0) {
      throw new Error("No valid temperature data available");
    }

    const sum = validTemperatures.reduce((total, temp) => total + temp, 0);
    const average = sum / validTemperatures.length;

    return {
      averageTemperature: average.toFixed(2),
      validCitiesCount: validTemperatures.length,
      totalCitiesCount: Object.keys(weatherData).length
    };
  } catch (error) {
    console.error("Error in aggregateWeatherData:", error.message);
    throw error;
  }
}

