<artifact type="application/vnd.ant.code" language="go">
package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/hex"
	"flag"
	"fmt"
	"io"
	"io/ioutil"
	"log"
	"os"
	"path/filepath"
	"sync"
)

// EncryptionResult represents the result of encrypting a file
type EncryptionResult struct {
	Filename string
	Success  bool
	Message  string
}

func main() {
	// Define command-line flags
	inputDir := flag.String("dir", "", "Directory containing files to encrypt")
	keyString := flag.String("key", "", "32-byte encryption key as hex string")
	outputDir := flag.String("outdir", "", "Directory to store encrypted files")
	flag.Parse()

	// Validate command-line arguments
	if *inputDir == "" || *keyString == "" {
		fmt.Println("Usage: program -dir=<input_directory> -key=<hex_key> [-outdir=<output_directory>]")
		flag.PrintDefaults()
		os.Exit(1)
	}

	// If output directory is not specified, use input directory
	if *outputDir == "" {
		*outputDir = *inputDir
	}

	// Create output directory if it doesn't exist
	if err := os.MkdirAll(*outputDir, 0755); err != nil {
		log.Fatalf("Failed to create output directory: %v", err)
	}

	// Decode key from hex string
	key, err := hex.DecodeString(*keyString)
	if err != nil || len(key) != 32 {
		log.Fatalf("Invalid key: must be a 32-byte (64 character) hex string")
	}

	// Get all files in the input directory
	files, err := ioutil.ReadDir(*inputDir)
	if err != nil {
		log.Fatalf("Failed to read directory: %v", err)
	}

	// Create a channel to collect encryption results
	resultChan := make(chan EncryptionResult)

	// Use a WaitGroup to wait for all encryption goroutines to complete
	var wg sync.WaitGroup

	// Start a goroutine for each file
	for _, file := range files {
		if file.IsDir() {
			continue
		}
		wg.Add(1)
		go encryptFile(filepath.Join(*inputDir, file.Name()), 
		              filepath.Join(*outputDir, file.Name()+".enc"), 
		              key, resultChan, &wg)
	}

	// Start a goroutine to close the results channel when all work is done
	go func() {
		wg.Wait()
		close(resultChan)
	}()

	// Process results as they come in
	successCount := 0
	failureCount := 0
	for result := range resultChan {
		if result.Success {
			log.Printf("SUCCESS: %s - %s", result.Filename, result.Message)
			successCount++
		} else {
			log.Printf("FAILURE: %s - %s", result.Filename, result.Message)
			failureCount++
		}
	}

	log.Printf("Encryption complete: %d files succeeded, %d files failed", successCount, failureCount)
}

// encryptFile encrypts a single file using AES-GCM and reports the result
func encryptFile(inputPath, outputPath string, key []byte, resultChan chan<- EncryptionResult, wg *sync.WaitGroup) {
	defer wg.Done()

	result := EncryptionResult{
		Filename: filepath.Base(inputPath),
		Success:  false,
		Message:  "",
	}

	// Read the input file
	plaintext, err := ioutil.ReadFile(inputPath)
	if err != nil {
		result.Message = fmt.Sprintf("Failed to read file: %v", err)
		resultChan <- result
		return
	}

	// Create a new AES cipher block
	block, err := aes.NewCipher(key)
	if err != nil {
		result.Message = fmt.Sprintf("Failed to create cipher: %v", err)
		resultChan <- result
		return
	}

	// Create a new GCM cipher
	gcm, err := cipher.NewGCM(block)
	if err != nil {
		result.Message = fmt.Sprintf("Failed to create GCM: %v", err)
		resultChan <- result
		return
	}

	// Create a nonce
	nonce := make([]byte, gcm.NonceSize())
	if _, err = io.ReadFull(rand.Reader, nonce); err != nil {
		result.Message = fmt.Sprintf("Failed to generate nonce: %v", err)
		resultChan <- result
		return
	}

	// Encrypt the plaintext
	ciphertext := gcm.Seal(nonce, nonce, plaintext, nil)

	// Write the encrypted file
	if err := ioutil.WriteFile(outputPath, ciphertext, 0644); err != nil {
		result.Message = fmt.Sprintf("Failed to write encrypted file: %v", err)
		resultChan <- result
		return
	}

	// Report success
	result.Success = true
	result.Message = "Encryption successful"
	resultChan <- result
}
