import java.util.*

// Task class with priority and operation
data class Task(val priority: Int, val operation: () -> Unit) : Comparable<Task> {
    override fun compareTo(other: Task): Int = other.priority.compareTo(priority)
}

// Task scheduler
class TaskScheduler {
    private val taskQueue = PriorityQueue<Task>()

    // Add a task with priority and operation
    fun addTask(priority: Int, operation: () -> Unit) {
        taskQueue.add(Task(priority, operation))
    }

    // Execute all tasks based on priority
    fun executeTasks() {
        while (taskQueue.isNotEmpty()) {
            val task = taskQueue.poll()
            task.operation()
        }
    }

    // Execute tasks with a specific executor function
    fun executeTasksWith(executor: (Task) -> Unit) {
        while (taskQueue.isNotEmpty()) {
            executor(taskQueue.poll())
        }
    }

    // Get number of pending tasks
    fun pendingTasksCount(): Int = taskQueue.size
}

// Example usage
fun main() {
    val scheduler = TaskScheduler()

    // Add tasks with different priorities
    scheduler.addTask(1) { println("Low priority task") }
    scheduler.addTask(5) { println("Medium priority task") }
    scheduler.addTask(10) { println("High priority task") }

    // Execute tasks in order of priority (highest first)
    scheduler.executeTasks()

    // Custom execution logic
    scheduler.addTask(3) { println("Task with priority 3") }
    scheduler.addTask(7) { println("Task with priority 7") }

    scheduler.executeTasksWith { task ->
        println("Executing task with priority: ${task.priority}")
        task.operation()
    }
}

fn authenticate_request(request: &http::Request<()>) -> bool {
    if let Some(auth_header) = request.headers().get("API_KEY") {
        if let Ok(token) = auth_header.to_str() {
            let api_secret = std::env::var("API_SECRET").unwrap_or_default();
            return token == api_secret;
        }
    }
    false
}

