type Book struct {
	ID     int    `json:"id"`
	Title  string `json:"title"`
	Author string `json:"author"`
	ISBN   string `json:"isbn"`
}

var (
	dbHost     = os.Getenv("DB_HOST")
	dbPort     = os.Getenv("DB_PORT")
	dbUser     = os.Getenv("DB_USER")
	dbPassword = os.Getenv("DB_PASSWORD")
	dbName     = os.Getenv("DB_NAME")
)

func getConnection() (*sql.DB, error) {
	connStr := fmt.Sprintf("host=%s port=%s user=%s password=%s dbname=%s sslmode=disable",
		dbHost, dbPort, dbUser, dbPassword, dbName)
	return sql.Open("postgres", connStr)
}

func createBook(w http.ResponseWriter, r *http.Request) {
	var book Book
	err := json.NewDecoder(r.Body).Decode(&book)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	db, err := getConnection()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	query := `INSERT INTO books (title, author, isbn) VALUES ($1, $2, $3) RETURNING id`
	err = db.QueryRow(query, book.Title, book.Author, book.ISBN).Scan(&book.ID)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(book)
}

func getBooks(w http.ResponseWriter, r *http.Request) {
	db, err := getConnection()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	rows, err := db.Query("SELECT id, title, author, isbn FROM books")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	var books []Book
	for rows.Next() {
		var book Book
		if err := rows.Scan(&book.ID, &book.Title, &book.Author, &book.ISBN); err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		books = append(books, book)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(books)
}

func getBook(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id, err := strconv.Atoi(params["id"])
	if err != nil {
		http.Error(w, "Invalid ID", http.StatusBadRequest)
		return
	}

	db, err := getConnection()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	var book Book
	query := "SELECT id, title, author, isbn FROM books WHERE id = $1"
	err = db.QueryRow(query, id).Scan(&book.ID, &book.Title, &book.Author, &book.ISBN)
	if err != nil {
		if err == sql.ErrNoRows {
			http.Error(w, "Book not found", http.StatusNotFound)
		} else {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		}
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(book)
}

func updateBook(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id, err := strconv.Atoi(params["id"])
	if err != nil {
		http.Error(w, "Invalid ID", http.StatusBadRequest)
		return
	}

	var book Book
	err = json.NewDecoder(r.Body).Decode(&book)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	book.ID = id

	db, err := getConnection()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	query := "UPDATE books SET title = $1, author = $2, isbn = $3 WHERE id = $4"
	result, err := db.Exec(query, book.Title, book.Author, book.ISBN, book.ID)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	rowsAffected, err := result.RowsAffected()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	if rowsAffected == 0 {
		http.Error(w, "Book not found", http.StatusNotFound)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(book)
}

func deleteBook(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id, err := strconv.Atoi(params["id"])
	if err != nil {
		http.Error(w, "Invalid ID", http.StatusBadRequest)
		return
	}

	db, err := getConnection()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	query := "DELETE FROM books WHERE id = $1"
	result, err := db.Exec(query, id)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	rowsAffected, err := result.RowsAffected()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	if rowsAffected == 0 {
		http.Error(w, "Book not found", http.StatusNotFound)
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

func main() {
	r := mux.NewRouter()

	r.HandleFunc("/books", getBooks).Methods("GET")
	r.HandleFunc("/books", createBook).Methods("POST")
	r.HandleFunc("/books/{id}", getBook).Methods("GET")
	r.HandleFunc("/books/{id}", updateBook).Methods("PUT")
	r.HandleFunc("/books/{id}", deleteBook).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8080", r))
}

package main

import (
	"encoding/json"
	"fmt"
	"log"
	"math/rand"
	"net/http"
	"sync"
	"time"
)

// User represents user information
type User struct {
	ID       int    `json:"id"`
	Name     string `json:"name"`
	Email    string `json:"email"`
	Age      int    `json:"age"`
	IsActive bool   `json:"is_active"`
}

// Response represents the final response to be sent to client
type Response struct {
	Status  string `json:"status"`
	Message string `json:"message"`
	Data    *User  `json:"data,omitempty"`
}

// Database simulates a database
type Database struct {
	mu    sync.Mutex
	users map[int]*User
}

// NewDatabase creates a new simulated database
func NewDatabase() *Database {
	db := &Database{
		users: make(map[int]*User),
	}

	// Populate with sample data
	for i := 1; i <= 100; i++ {
		db.users[i] = &User{
			ID:       i,
			Name:     fmt.Sprintf("User %d", i),
			Email:    fmt.Sprintf("user%d@example.com", i),
			Age:      20 + rand.Intn(40),
			IsActive: rand.Intn(2) == 1,
		}
	}

	return db
}

// FetchUser retrieves a user from the database
func (db *Database) FetchUser(id int) (*User, error) {
	db.mu.Lock()
	defer db.mu.Unlock()

	// Simulate database latency
	time.Sleep(time.Duration(100+rand.Intn(300)) * time.Millisecond)

	user, exists := db.users[id]
	if !exists {
		return nil, fmt.Errorf("user with ID %d not found", id)
	}

	// Return a copy of the user
	userCopy := *user
	return &userCopy, nil
}

// ProcessResult processes user data and determines if it's valid
func ProcessData(user *User) (bool, string) {
	// Simulate processing time
	time.Sleep(time.Duration(50+rand.Intn(150)) * time.Millisecond)

	// Simple validation rules
	if !user.IsActive {
		return false, "user account is inactive"
	}

	if user.Age < 18 {
		return false, "user is underage"
	}

	return true, "user data validated successfully"
}

func main() {
	// Seed the random number generator
	rand.Seed(time.Now().UnixNano())

	// Initialize the database
	db := NewDatabase()

	// Set up the HTTP server
	http.HandleFunc("/user", func(w http.ResponseWriter, r *http.Request) {
		// Parse user ID from query parameter
		idStr := r.URL.Query().Get("id")
		if idStr == "" {
			http.Error(w, "Missing user ID", http.StatusBadRequest)
			return
		}

		var userID int
		_, err := fmt.Sscanf(idStr, "%d", &userID)
		if err != nil {
			http.Error(w, "Invalid user ID", http.StatusBadRequest)
			return
		}

		// Create channels for communication between goroutines
		fetchCh := make(chan *User)
		errCh := make(chan error)
		resultCh := make(chan Response)

		// Start goroutine to fetch user data
		go func() {
			user, err := db.FetchUser(userID)
			if err != nil {
				errCh <- err
				return
			}
			fetchCh <- user
		}()

		// Start goroutine to process the data once fetched
		go func() {
			select {
			case user := <-fetchCh:
				// Process the user data
				valid, message := ProcessData(user)

				var status string
				if valid {
					status = "success"
				} else {
					status = "error"
				}

				resultCh <- Response{
					Status:  status,
					Message: message,
					Data:    user,
				}

			case err := <-errCh:
				// Handle error
				resultCh <- Response{
					Status:  "error",
					Message: err.Error(),
				}
			}
		}()

		// Wait for the result and send response
		select {
		case result := <-resultCh:
			w.Header().Set("Content-Type", "application/json")
			json.NewEncoder(w).Encode(result)

		case <-time.After(2 * time.Second):
			// Timeout handling
			w.Header().Set("Content-Type", "application/json")
			json.NewEncoder(w).Encode(Response{
				Status:  "error",
				Message: "request timed out",
			})
		}
	})

	// Start the server
	fmt.Println("Server starting on :8080...")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

fn convert_temperatures(celsius_temps: Vec<f32>) -> Vec<f32> {
    // Convert each temperature using pattern matching based on temperature ranges
    celsius_temps.iter().map(|&temp| {
        // Pattern match on temperature ranges
        match temp {
            // Freezing range: below 0°C
            t if t < 0.0 => {
                // For freezing temperatures, apply standard conversion
                (t * 9.0/5.0) + 32.0
            },
            // Cold range: 0°C to 15°C
            t if t >= 0.0 && t <= 15.0 => {
                // For cold temperatures, apply standard conversion
                (t * 9.0/5.0) + 32.0
            },
            // Warm range: 16°C to 30°C
            t if t > 15.0 && t <= 30.0 => {
                // For warm temperatures, apply standard conversion
                (t * 9.0/5.0) + 32.0
            },
            // Hot range: above 30°C
            _ => {
                // For hot temperatures, apply standard conversion
                // This catch-all pattern handles all remaining cases (t > 30.0)
                (temp * 9.0/5.0) + 32.0
            }
        }
    }).collect()
}

// Example usage
fn main() {
    let celsius_temperatures = vec![-10.0, 0.0, 5.0, 20.0, 35.0];
    let fahrenheit_temperatures = convert_temperatures(celsius_temperatures);

    // Display the converted temperatures
    for (i, temp) in fahrenheit_temperatures.iter().enumerate() {
        println!("Temperature {}: {:.1}°F", i + 1, temp);
    }
}

const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const app = express();
const port = 3000;

// Configure storage
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, 'uploads/');
  },
  filename: (req, file, cb) => {
    cb(null, Date.now() + path.extname(file.originalname));
  }
});

// File filter to allow only jpeg and png
const fileFilter = (req, file, cb) => {
  if (file.mimetype === 'image/jpeg' || file.mimetype === 'image/png') {
    cb(null, true);
  } else {
    cb(new Error('Only JPEG and PNG images are allowed'), false);
  }
};

const upload = multer({ storage, fileFilter });

// Ensure uploads directory exists
if (!fs.existsSync('uploads/')) {
  fs.mkdirSync('uploads/');
}

// Middleware to log file info using arrow function
const logFileInfo = (req, res, next) => {
  try {
    if (req.file) {
      console.log(`File name: ${req.file.filename}`);
      console.log(`File size: ${req.file.size} bytes`);
    }
    next();
  } catch (error) {
    console.error(`Error processing file: ${error.message}`);
    next(error);
  }
};

