import io.jsonwebtoken.Claims
import io.jsonwebtoken.Jwts
import io.jsonwebtoken.SignatureAlgorithm
import io.jsonwebtoken.security.Keys
import io.ktor.application.*
import io.ktor.auth.*
import io.ktor.auth.jwt.*
import io.ktor.features.*
import io.ktor.http.*
import io.ktor.response.*
import io.ktor.routing.*
import io.ktor.server.engine.*
import io.ktor.server.netty.*
import java.security.Key
import java.util.*

fun main() {
    val jwtSecret = Keys.secretKeyFor(SignatureAlgorithm.HS256)
    val authService = AuthService(jwtSecret)

    embeddedServer(Netty, port = 8080) {
        install(ContentNegotiation)
        install(CORS) {
            method(HttpMethod.Options)
            method(HttpMethod.Get)
            method(HttpMethod.Post)
            method(HttpMethod.Put)
            method(HttpMethod.Delete)
            header(HttpHeaders.Authorization)
            allowCredentials = true
            anyHost()
        }

        install(Authentication) {
            jwt("auth-jwt") {
                verifier(
                    Jwts.parserBuilder()
                        .setSigningKey(jwtSecret)
                        .build()
                )
                validate { credential ->
                    if (credential.payload.subject != null) {
                        JWTPrincipal(credential.payload)
                    } else {
                        null
                    }
                }
            }
        }

        routing {
            authenticate("auth-jwt") {
                get("/api/protected") {
                    val principal = call.principal<JWTPrincipal>()
                    val userId = principal?.payload?.subject
                    val roles = principal?.payload?.get("roles", List::class.java) as? List<String>

                    // Lambda for role-based access control
                    val hasAccess: (List<String>?, Set<String>) -> Boolean = { userRoles, requiredRoles ->
                        userRoles?.any { it in requiredRoles } ?: false
                    }

                    if (userId != null && hasAccess(roles, setOf("ADMIN", "USER"))) {
                        call.respond(HttpStatusCode.OK, mapOf("message" to "Access granted", "userId" to userId))
                    } else {
                        call.respond(HttpStatusCode.Forbidden, mapOf("error" to "Insufficient permissions"))
                    }
                }

                get("/api/admin") {
                    val principal = call.principal<JWTPrincipal>()
                    val userId = principal?.payload?.subject
                    val roles = principal?.payload?.get("roles", List::class.java) as? List<String>

                    // Configurable lambda for dynamic permission checking
                    val checkPermission: (List<String>?, String) -> Boolean = { userRoles, requiredRole ->
                        userRoles?.contains(requiredRole) ?: false
                    }

                    if (userId != null && checkPermission(roles, "ADMIN")) {
                        call.respond(HttpStatusCode.OK, mapOf("message" to "Admin access granted", "userId" to userId))
                    } else {
                        call.respond(HttpStatusCode.Forbidden, mapOf("error" to "Admin access required"))
                    }
                }
            }
        }
    }.start(wait = true)
}

class AuthService(private val jwtSecret: Key) {
    fun generateToken(userId: String, roles: List<String>): String {
        return Jwts.builder()
            .setSubject(userId)
            .setIssuedAt(Date())
            .setExpiration(Date(System.currentTimeMillis() + 3600000)) // 1 hour
            .claim("roles", roles)
            .signWith(jwtSecret)
            .compact()
    }

    fun validateToken(token: String): Claims {
        return Jwts.parserBuilder()
            .setSigningKey(jwtSecret)
            .build()
            .parseClaimsJws(token)
            .body
    }

    // Function utilizing lambda to check access permissions
    fun checkAccess(roles: List<String>?, permissionChecker: (List<String>?) -> Boolean): Boolean {
        return permissionChecker(roles)
    }
}

