func concurrentSum(numbers []int) int {
    if len(numbers) == 0 {
        return 0
    }

    n := len(numbers)
    ch := make(chan int)

    // Split the work between goroutines
    for i := 0; i < n; i++ {
        go func(index int) {
            ch <- numbers[index]
        }(i)
    }

    // Collect and sum results
    sum := 0
    for i := 0; i < n; i++ {
        sum += <-ch
    }

    return sum
}

fun String.isPalindrome(): Boolean {
    val cleanString = this.lowercase().filter { it.isLetterOrDigit() }
    val isPal: (String) -> Boolean = { str ->
        str == str.reversed()
    }
    return isPal(cleanString)
}

fun String.isPalindrome(): Boolean {
    val cleanString = this.lowercase().filter { it.isLetterOrDigit() }
    return cleanString == cleanString.reversed()
}
